import{_ as t,o as s,c as n,ag as e}from"./chunks/framework.BVdG3tbf.js";const b=JSON.parse('{"title":"热阻计算器","description":"","frontmatter":{},"headers":[],"relativePath":"tools/thermal-resistance.md","filePath":"tools/thermal-resistance.md","lastUpdated":1774417890000}'),l={name:"tools/thermal-resistance.md"};function p(d,a,i,r,o,h){return s(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="热阻计算器" tabindex="-1">热阻计算器 <a class="header-anchor" href="#热阻计算器" aria-label="Permalink to &quot;热阻计算器&quot;">​</a></h1><p>热阻是评估电子封装散热性能的关键参数。</p><h2 id="📚-热阻基础" tabindex="-1">📚 热阻基础 <a class="header-anchor" href="#📚-热阻基础" aria-label="Permalink to &quot;📚 热阻基础&quot;">​</a></h2><h3 id="热阻定义" tabindex="-1">热阻定义 <a class="header-anchor" href="#热阻定义" aria-label="Permalink to &quot;热阻定义&quot;">​</a></h3><p>热阻表示温度差与热功率的比值：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>R_th = ΔT / Q = (T_j - T_a) / P</span></span></code></pre></div><p>其中：</p><ul><li><strong>R_th</strong> - 热阻 (K/W 或 °C/W)</li><li><strong>ΔT</strong> - 温差 (K 或 °C)</li><li><strong>Q</strong> - 热功率 (W)</li><li><strong>T_j</strong> - 结温 (°C)</li><li><strong>T_a</strong> - 环境温度 (°C)</li><li><strong>P</strong> - 功耗 (W)</li></ul><h3 id="热阻类型" tabindex="-1">热阻类型 <a class="header-anchor" href="#热阻类型" aria-label="Permalink to &quot;热阻类型&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>总热阻 R_ja = R_jc + R_cs + R_sa</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌─────────────────────────────────┐</span></span>
<span class="line"><span>│  芯片 (Junction)  T_j          │ ← 结温</span></span>
<span class="line"><span>├─────────────────────────────────┤</span></span>
<span class="line"><span>│  R_jc (结到外壳)               │</span></span>
<span class="line"><span>├─────────────────────────────────┤</span></span>
<span class="line"><span>│  封装外壳 (Case)  T_c          │ ← 壳温</span></span>
<span class="line"><span>├─────────────────────────────────┤</span></span>
<span class="line"><span>│  R_cs (外壳到散热器)           │ ← 界面热阻</span></span>
<span class="line"><span>├─────────────────────────────────┤</span></span>
<span class="line"><span>│  散热器 (Sink)                 │</span></span>
<span class="line"><span>├─────────────────────────────────┤</span></span>
<span class="line"><span>│  R_sa (散热器到环境)           │</span></span>
<span class="line"><span>├─────────────────────────────────┤</span></span>
<span class="line"><span>│  环境 (Ambient)  T_a           │ ← 环境温度</span></span>
<span class="line"><span>└─────────────────────────────────┘</span></span></code></pre></div><h2 id="🧮-热阻计算" tabindex="-1">🧮 热阻计算 <a class="header-anchor" href="#🧮-热阻计算" aria-label="Permalink to &quot;🧮 热阻计算&quot;">​</a></h2><h3 id="计算器-1-简单热阻计算" tabindex="-1">计算器 1：简单热阻计算 <a class="header-anchor" href="#计算器-1-简单热阻计算" aria-label="Permalink to &quot;计算器 1：简单热阻计算&quot;">​</a></h3><p><strong>输入参数：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>功耗 P:        _____ W</span></span>
<span class="line"><span>结温 T_j:      _____ °C</span></span>
<span class="line"><span>环境温度 T_a:  _____ °C</span></span></code></pre></div><p><strong>计算：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ΔT = T_j - T_a</span></span>
<span class="line"><span>R_th = ΔT / P</span></span></code></pre></div><p><strong>示例：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入:</span></span>
<span class="line"><span>├── 功耗: 10 W</span></span>
<span class="line"><span>├── 结温: 85 °C</span></span>
<span class="line"><span>└── 环境温度: 25 °C</span></span>
<span class="line"><span></span></span>
<span class="line"><span>计算:</span></span>
<span class="line"><span>├── ΔT = 85 - 25 = 60 °C</span></span>
<span class="line"><span>└── R_th = 60 / 10 = 6 °C/W</span></span></code></pre></div><h3 id="计算器-2-材料热阻计算" tabindex="-1">计算器 2：材料热阻计算 <a class="header-anchor" href="#计算器-2-材料热阻计算" aria-label="Permalink to &quot;计算器 2：材料热阻计算&quot;">​</a></h3><p><strong>公式：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>R = L / (k × A)</span></span></code></pre></div><p>其中：</p><ul><li><strong>L</strong> - 材料厚度 (m)</li><li><strong>k</strong> - 热导率 (W/(m·K))</li><li><strong>A</strong> - 面积 (m²)</li></ul><p><strong>示例计算：</strong></p><table tabindex="0"><thead><tr><th>材料</th><th>厚度 (mm)</th><th>热导率 (W/m·K)</th><th>面积 (mm²)</th><th>热阻 (°C/W)</th></tr></thead><tbody><tr><td>芯片 (Si)</td><td>0.5</td><td>148</td><td>100</td><td>0.034</td></tr><tr><td>焊料</td><td>0.1</td><td>57</td><td>100</td><td>0.018</td></tr><tr><td>基板 (FR-4)</td><td>1.6</td><td>0.3</td><td>400</td><td>13.3</td></tr><tr><td>热界面材料</td><td>0.2</td><td>3</td><td>100</td><td>0.67</td></tr></tbody></table><h3 id="计算器-3-对流热阻" tabindex="-1">计算器 3：对流热阻 <a class="header-anchor" href="#计算器-3-对流热阻" aria-label="Permalink to &quot;计算器 3：对流热阻&quot;">​</a></h3><p><strong>公式：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>R_conv = 1 / (h × A)</span></span></code></pre></div><p>其中：</p><ul><li><strong>h</strong> - 对流系数 (W/(m²·K))</li><li><strong>A</strong> - 散热面积 (m²)</li></ul><p><strong>自然对流系数：</strong></p><table tabindex="0"><thead><tr><th>表面</th><th>h (W/m²·K)</th></tr></thead><tbody><tr><td>垂直板</td><td>5-25</td></tr><tr><td>水平板（热面朝上）</td><td>5-25</td></tr><tr><td>水平板（热面朝下）</td><td>2-12</td></tr><tr><td>小型元件</td><td>10-20</td></tr></tbody></table><p><strong>强制对流系数：</strong></p><table tabindex="0"><thead><tr><th>情况</th><th>h (W/m²·K)</th></tr></thead><tbody><tr><td>空气（低速）</td><td>25-100</td></tr><tr><td>空气（高速）</td><td>100-500</td></tr><tr><td>水（低速）</td><td>500-5000</td></tr><tr><td>水（高速）</td><td>5000-50000</td></tr></tbody></table><h2 id="📊-典型热阻值" tabindex="-1">📊 典型热阻值 <a class="header-anchor" href="#📊-典型热阻值" aria-label="Permalink to &quot;📊 典型热阻值&quot;">​</a></h2><h3 id="封装热阻参考" tabindex="-1">封装热阻参考 <a class="header-anchor" href="#封装热阻参考" aria-label="Permalink to &quot;封装热阻参考&quot;">​</a></h3><table tabindex="0"><thead><tr><th>封装类型</th><th>R_jc (°C/W)</th><th>R_ja (°C/W)</th></tr></thead><tbody><tr><td>TO-220</td><td>1-3</td><td>50-70</td></tr><tr><td>TO-247</td><td>0.5-2</td><td>40-60</td></tr><tr><td>D2PAK</td><td>1-3</td><td>40-60</td></tr><tr><td>QFN 5×5</td><td>5-15</td><td>30-50</td></tr><tr><td>BGA</td><td>2-10</td><td>25-40</td></tr><tr><td>LGA</td><td>1-5</td><td>20-35</td></tr></tbody></table><h3 id="热界面材料热阻" tabindex="-1">热界面材料热阻 <a class="header-anchor" href="#热界面材料热阻" aria-label="Permalink to &quot;热界面材料热阻&quot;">​</a></h3><table tabindex="0"><thead><tr><th>材料类型</th><th>热阻 (°C·cm²/W)</th></tr></thead><tbody><tr><td>硅脂</td><td>0.05-0.2</td></tr><tr><td>相变材料</td><td>0.1-0.3</td></tr><tr><td>导热垫</td><td>0.5-2.0</td></tr><tr><td>铟箔</td><td>0.02-0.05</td></tr><tr><td>焊料</td><td>0.01-0.03</td></tr></tbody></table><h2 id="📐-实例计算" tabindex="-1">📐 实例计算 <a class="header-anchor" href="#📐-实例计算" aria-label="Permalink to &quot;📐 实例计算&quot;">​</a></h2><h3 id="实例-1-功率芯片散热" tabindex="-1">实例 1：功率芯片散热 <a class="header-anchor" href="#实例-1-功率芯片散热" aria-label="Permalink to &quot;实例 1：功率芯片散热&quot;">​</a></h3><p><strong>问题：</strong></p><ul><li>芯片功耗：15 W</li><li>最大结温：125 °C</li><li>环境温度：40 °C</li><li>封装热阻 R_jc：2 °C/W</li></ul><p><strong>计算：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>允许温升: ΔT = 125 - 40 = 85 °C</span></span>
<span class="line"><span>允许总热阻: R_ja = 85 / 15 = 5.67 °C/W</span></span>
<span class="line"><span>需要散热器热阻: R_sa = R_ja - R_jc = 5.67 - 2 = 3.67 °C/W</span></span></code></pre></div><p><strong>结论：</strong> 需要热阻小于 3.67 °C/W 的散热器。</p><h3 id="实例-2-pcb-散热分析" tabindex="-1">实例 2：PCB 散热分析 <a class="header-anchor" href="#实例-2-pcb-散热分析" aria-label="Permalink to &quot;实例 2：PCB 散热分析&quot;">​</a></h3><p><strong>问题：</strong></p><ul><li>多个热源：5 个芯片</li><li>总功耗：25 W</li><li>PCB 尺寸：100 mm × 100 mm</li><li>PCB 热导率（面内）：20 W/(m·K)</li></ul><p><strong>计算：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PCB 面内热阻:</span></span>
<span class="line"><span>├── 等效传导长度: 50 mm</span></span>
<span class="line"><span>├── 热导率: 20 W/(m·K)</span></span>
<span class="line"><span>├── 面积: 100 mm × 1.6 mm = 160 mm²</span></span>
<span class="line"><span>└── R = 0.05 / (20 × 0.00016) = 15.6 °C/W</span></span>
<span class="line"><span></span></span>
<span class="line"><span>对流热阻:</span></span>
<span class="line"><span>├── 对流系数: 10 W/(m²·K)</span></span>
<span class="line"><span>├── 面积: 100 × 100 mm² = 0.01 m²</span></span>
<span class="line"><span>└── R = 1 / (10 × 0.01) = 10 °C/W</span></span></code></pre></div><h2 id="🔧-热阻优化" tabindex="-1">🔧 热阻优化 <a class="header-anchor" href="#🔧-热阻优化" aria-label="Permalink to &quot;🔧 热阻优化&quot;">​</a></h2><h3 id="降低热阻的方法" tabindex="-1">降低热阻的方法 <a class="header-anchor" href="#降低热阻的方法" aria-label="Permalink to &quot;降低热阻的方法&quot;">​</a></h3><table tabindex="0"><thead><tr><th>措施</th><th>目标</th><th>效果</th></tr></thead><tbody><tr><td>使用高导热材料</td><td>减小 R_jc</td><td>显著</td></tr><tr><td>优化热界面</td><td>减小 R_cs</td><td>中等</td></tr><tr><td>增大散热器</td><td>减小 R_sa</td><td>显著</td></tr><tr><td>强制对流</td><td>减小 R_sa</td><td>显著</td></tr><tr><td>热通孔</td><td>改善散热路径</td><td>中等</td></tr></tbody></table><h3 id="热通孔优化" tabindex="-1">热通孔优化 <a class="header-anchor" href="#热通孔优化" aria-label="Permalink to &quot;热通孔优化&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>热通孔参数:</span></span>
<span class="line"><span>├── 直径: 0.3 mm</span></span>
<span class="line"><span>├── 间距: 1.0 mm</span></span>
<span class="line"><span>├── 填充: 铜</span></span>
<span class="line"><span>└── 热阻改善: 20-40%</span></span></code></pre></div><h2 id="📖-相关内容" tabindex="-1">📖 相关内容 <a class="header-anchor" href="#📖-相关内容" aria-label="Permalink to &quot;📖 相关内容&quot;">​</a></h2><ul><li><a href="/simu-learn/tools/mesh-estimator.html">网格估算器</a></li><li><a href="/simu-learn/tools/materials.html">材料数据库</a></li></ul><hr><div class="tip custom-block"><p class="custom-block-title">提示</p><p>热阻计算是热设计的第一步，建议先进行理论计算再进行仿真验证。</p></div>`,60)])])}const g=t(l,[["render",p]]);export{b as __pageData,g as default};
